// Divide o array retornado pelo RPC em items individuais
const body = $input.first().json;
const items = Array.isArray(body) ? body : [];

if (items.length === 0) return [];

return items.map(item => ({
  json: {
    queue_id:     item.id,
    message_id:   item.message_id,
    group_jid:    item.group_jid,
    sender_jid:   item.payload?.sender_jid || null,
    sender_name:  item.payload?.sender_name || null,
    is_from_team: item.payload?.is_from_team || false,
    content_type: item.payload?.content_type || 'text',
    content_text: item.payload?.content_text || null,
    timestamp:    item.payload?.timestamp || item.created_at,
    created_at:   item.created_at
  }
}));

/*
  Classificação de tópico em 6 etapas:
  1. Lookup mentorado por group_jid
  2. Fetch tópicos abertos do grupo
  3. Fetch últimas 30 mensagens do grupo
  4. Montar prompt + chamar Claude Haiku
  5. Parsear resposta: assign ou create new topic
  6. Inserir wa_message na tabela processada
*/

const item = $input.first().json;
const SUPABASE_URL  = $env.SUPABASE_URL;
const SUPABASE_KEY  = $env.SUPABASE_SERVICE_KEY;
const CLAUDE_KEY    = $env.CLAUDE_API_KEY;

const sbHeaders = {
  'apikey':        SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type':  'application/json',
};

// ── 1. Lookup mentorado ──────────────────────────────────────
let mentoradoId = null;
let mentoradoNome = null;
try {
  const mRes = await $helpers.httpRequest({
    method: 'POST',
    url:    `${SUPABASE_URL}/rest/v1/rpc/get_mentorado_by_group`,
    headers: sbHeaders,
    body:    JSON.stringify({ p_group_jid: item.group_jid }),
  });
  const m = JSON.parse(mRes.body);
  if (m?.id) { mentoradoId = m.id; mentoradoNome = m.nome; }
} catch(e) {
  console.log('Mentorado lookup failed (non-critical):', e.message);
}

// ── 2. Fetch tópicos abertos do grupo ────────────────────────
let openTopics = [];
try {
  const tRes = await $helpers.httpRequest({
    method: 'GET',
    url:    `${SUPABASE_URL}/rest/v1/wa_topics` +
            `?group_jid=eq.${encodeURIComponent(item.group_jid)}` +
            `&status=in.(open,active)` +
            `&order=last_message_at.desc` +
            `&limit=10` +
            `&select=id,title,summary,last_message_at,message_count`,
    headers: sbHeaders,
  });
  openTopics = JSON.parse(tRes.body) || [];
} catch(e) {
  console.log('Open topics fetch failed:', e.message);
}

// ── 3. Fetch últimas mensagens do grupo (contexto) ────────────
let recentMsgs = [];
try {
  const mRes = await $helpers.httpRequest({
    method: 'GET',
    url:    `${SUPABASE_URL}/rest/v1/wa_messages` +
            `?group_jid=eq.${encodeURIComponent(item.group_jid)}` +
            `&order=timestamp.desc` +
            `&limit=30` +
            `&select=timestamp,sender_name,content_text`,
    headers: sbHeaders,
  });
  recentMsgs = (JSON.parse(mRes.body) || []).reverse();
} catch(e) {
  console.log('Recent messages fetch failed:', e.message);
}

// ── 4. Montar prompt e chamar Claude ─────────────────────────
const topicsCtx = openTopics.length > 0
  ? openTopics.map(t =>
      `[ID:${t.id}] "${t.title}" — Último: ${t.last_message_at}\n  Resumo: ${t.summary || 'Sem resumo'}`
    ).join('\n')
  : 'Nenhum tópico aberto no momento';

const msgsCtx = recentMsgs.length > 0
  ? recentMsgs.map(m =>
      `[${m.timestamp}] ${m.sender_name || 'Usuário'}: ${m.content_text || '[mídia]'}`
    ).join('\n')
  : 'Sem mensagens anteriores';

const userPrompt =
  `TÓPICOS ABERTOS ATUALMENTE:\n${topicsCtx}\n\n` +
  `ÚLTIMAS 30 MENSAGENS DO GRUPO (contexto geral):\n${msgsCtx}\n\n` +
  `NOVA MENSAGEM:\n` +
  `[${item.timestamp}] ${item.sender_name || item.sender_jid || 'Usuário'}: ${item.content_text || '[mídia]'}\n\n` +
  `INSTRUÇÃO:\n` +
  `1. Analise se a nova mensagem pertence a um dos tópicos abertos acima\n` +
  `2. Se pertence: retorne o topic_id com confidence\n` +
  `3. Se é novo tópico: retorne action:new com título sugerido e tipo\n` +
  `4. REGRA CRÍTICA: Não misture tópicos diferentes\n\n` +
  `RESPONDA APENAS com JSON válido (sem markdown):\n` +
  `{"action":"assign"|"new","topic_id":"uuid"|null,"topic_type":"revisao|demanda|plano|duvida|call|celebracao|dossie|pos_call|feedback|geral","new_topic_title":"string se new","confidence":0.0,"reasoning":"breve"}`;

let classification = null;
try {
  const claudeRes = await $helpers.httpRequest({
    method: 'POST',
    url:    'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key':         CLAUDE_KEY,
      'anthropic-version': '2023-06-01',
      'Content-Type':      'application/json',
    },
    body: JSON.stringify({
      model:      'claude-haiku-4-5-20251001',
      max_tokens: 300,
      system:     'Você é um classificador de tópicos para grupos de WhatsApp de mentoria empresarial. Responda APENAS com JSON válido, sem texto adicional.',
      messages:   [{ role: 'user', content: userPrompt }],
    }),
  });
  const claudeData = JSON.parse(claudeRes.body);
  const text = claudeData.content?.[0]?.text || '';
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) classification = JSON.parse(jsonMatch[0]);
} catch(e) {
  console.log('Claude API error:', e.message);
}

// Fallback se Claude falhar
if (!classification) {
  classification = {
    action: 'new',
    topic_type: 'geral',
    new_topic_title: (item.content_text || 'Nova Conversa').substring(0, 60),
    confidence: 0.3,
    reasoning: 'Fallback — Claude indisponível'
  };
}

// ── 5. Criar ou atualizar tópico ─────────────────────────────
let topicId = null;

if (classification.action === 'assign' && classification.topic_id && classification.confidence >= 0.75) {
  // Atribuir a tópico existente
  topicId = classification.topic_id;
  try {
    await $helpers.httpRequest({
      method:  'POST',
      url:     `${SUPABASE_URL}/rest/v1/rpc/increment_topic_message_count`,
      headers: sbHeaders,
      body:    JSON.stringify({ p_topic_id: topicId, p_timestamp: item.timestamp }),
    });
  } catch(e) { console.log('increment_topic_message_count error:', e.message); }

} else {
  // Criar novo tópico
  // Buscar type_id a partir do slug
  let typeId = null;
  try {
    const typeRes = await $helpers.httpRequest({
      method:  'GET',
      url:     `${SUPABASE_URL}/rest/v1/wa_topic_types?slug=eq.${classification.topic_type}&select=id`,
      headers: sbHeaders,
    });
    const types = JSON.parse(typeRes.body) || [];
    typeId = types[0]?.id || null;
  } catch(e) { console.log('type lookup error:', e.message); }

  const newTopic = {
    group_jid:        item.group_jid,
    mentorado_id:     mentoradoId,
    type_id:          typeId,
    title:            (classification.new_topic_title || (item.content_text || 'Nova Conversa')).substring(0, 120),
    status:           'open',
    confidence:       classification.confidence,
    message_count:    1,
    first_message_at: item.timestamp,
    last_message_at:  item.timestamp,
    ai_keywords:      [],
    ai_context_hash:  null,
  };

  try {
    const createRes = await $helpers.httpRequest({
      method:  'POST',
      url:     `${SUPABASE_URL}/rest/v1/wa_topics`,
      headers: { ...sbHeaders, 'Prefer': 'return=representation' },
      body:    JSON.stringify(newTopic),
    });
    const created = JSON.parse(createRes.body);
    topicId = (Array.isArray(created) ? created[0] : created)?.id || null;

    // Log evento de criação
    if (topicId) {
      await $helpers.httpRequest({
        method:  'POST',
        url:     `${SUPABASE_URL}/rest/v1/wa_topic_events`,
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body:    JSON.stringify({
          topic_id:   topicId,
          event_type: 'created',
          payload:    { type: classification.topic_type, confidence: classification.confidence, reasoning: classification.reasoning },
          created_by: 'ai',
        }),
      });
    }
  } catch(e) { console.log('create topic error:', e.message); }
}

// ── 6. Inserir mensagem processada ───────────────────────────
if (topicId) {
  try {
    await $helpers.httpRequest({
      method:  'POST',
      url:     `${SUPABASE_URL}/rest/v1/wa_messages`,
      headers: { ...sbHeaders, 'Prefer': 'return=minimal,resolution=ignore-duplicates' },
      body:    JSON.stringify({
        message_id:        item.message_id,
        group_jid:         item.group_jid,
        mentorado_id:      mentoradoId,
        topic_id:          topicId,
        topic_confidence:  classification.confidence,
        sender_jid:        item.sender_jid,
        sender_name:       item.sender_name,
        is_from_team:      item.is_from_team || false,
        content_type:      item.content_type || 'text',
        content_text:      item.content_text,
        timestamp:         item.timestamp,
      }),
    });
  } catch(e) { console.log('insert wa_message error:', e.message); }
}

return [{
  json: {
    queue_id:   item.queue_id,
    message_id: item.message_id,
    topic_id:   topicId,
    action:     classification.action,
    confidence: classification.confidence,
    success:    !!topicId,
  }
}];

// Marca item da fila como 'error' em caso de falha
const errItem = $input.first().json;
const queueId = errItem.queue_id;

if (queueId) {
  try {
    await $helpers.httpRequest({
      method:  'PATCH',
      url:     `${$env.SUPABASE_URL}/rest/v1/wa_message_queue?id=eq.${queueId}`,
      headers: {
        'apikey':        $env.SUPABASE_SERVICE_KEY,
        'Authorization': `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
        'Content-Type':  'application/json',
        'Prefer':        'return=minimal',
      },
      body: JSON.stringify({
        status:    'error',
        error_msg: errItem.error?.message || 'Erro desconhecido no classificador',
      }),
    });
  } catch(e) { /* silently fail */ }
}

return [{ json: { handled: true, queue_id: queueId } }];
